from typing import List

class Solution:
    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        n = len(nums)

        if k == 1:
            return True

        if k > n:
            return False

        total_sum = sum(nums)

        if total_sum % k != 0:
            return False

        target_sum = total_sum // k

        nums.sort(reverse=True)

        used = [False] * n

        def backtrack(k_remaining, current_subset_sum, start_idx):
            if k_remaining == 0:
                return True

            if current_subset_sum == target_sum:
                return backtrack(k_remaining - 1, 0, 0)

            for i in range(start_idx, n):
                if i > 0 and nums[i] == nums[i-1] and not used[i-1]:
                    continue

                if not used[i] and current_subset_sum + nums[i] <= target_sum:
                    used[i] = True
                    if backtrack(k_remaining, current_subset_sum + nums[i], i + 1):
                        return True
                    used[i] = False

            return False

        return backtrack(k, 0, 0)
